self_improved:
def normalize(s):
    return s.strip().lower()

def dedup(xs):
    # dedup collapses by normalized form; the dependency on normalize()
    # is explicit, so changes to normalize() intentionally flow here.
    return sorted(set(normalize(x) for x in xs))
